from collections import defaultdict

class Solution:
    def matrixRankTransform(self, matrix):
        m, n = len(matrix), len(matrix[0])
        rank_row = [0] * m
        rank_col = [0] * n
        value_cells = defaultdict(list)
        for r in range(m):
            for c in range(n):
                value_cells[matrix[r][c]].append((r, c))
        answer = [[0] * n for _ in range(m)]
        for v in sorted(value_cells):
            cells = value_cells[v]
            parent = {}

            def find(x):
                while parent[x] != x:
                    parent[x] = parent[parent[x]]
                    x = parent[x]
                return x

            def union(x, y):
                px, py = find(x), find(y)
                if px != py:
                    parent[px] = py

            for (r, c) in cells:
                rk = ('r', r)
                ck = ('c', c)
                if rk not in parent:
                    parent[rk] = rk
                if ck not in parent:
                    parent[ck] = ck
                union(rk, ck)
            groups = defaultdict(list)
            for (r, c) in cells:
                groups[find(('r', r))].append((r, c))
            for group_cells in groups.values():
                max_rank = 0
                for (r, c) in group_cells:
                    max_rank = max(max_rank, rank_row[r], rank_col[c])
                new_rank = max_rank + 1
                for (r, c) in group_cells:
                    rank_row[r] = new_rank
                    rank_col[c] = new_rank
                    answer[r][c] = new_rank
        return answer

