var matrixRankTransform = function(matrix) {
    const m = matrix.length, n = matrix[0].length;
    const rankRow = new Array(m).fill(0);
    const rankCol = new Array(n).fill(0);
    const valueCells = new Map();
    for (let r = 0; r < m; r++) {
        for (let c = 0; c < n; c++) {
            const v = matrix[r][c];
            if (!valueCells.has(v)) valueCells.set(v, []);
            valueCells.get(v).push([r, c]);
        }
    }
    const values = Array.from(valueCells.keys()).sort((a, b) => a - b);
    const answer = Array.from({ length: m }, () => new Array(n).fill(0));
    for (const v of values) {
        const cells = valueCells.get(v);
        const parent = new Map();
        const find = (x) => {
            while (parent.get(x) !== x) {
                parent.set(x, parent.get(parent.get(x)));
                x = parent.get(x);
            }
            return x;
        };
        const union = (x, y) => {
            const px = find(x), py = find(y);
            if (px !== py) parent.set(px, py);
        };
        for (const [r, c] of cells) {
            const rk = 'r' + r, ck = 'c' + c;
            if (!parent.has(rk)) parent.set(rk, rk);
            if (!parent.has(ck)) parent.set(ck, ck);
            union(rk, ck);
        }
        const groups = new Map();
        for (const [r, c] of cells) {
            const root = find('r' + r);
            if (!groups.has(root)) groups.set(root, []);
            groups.get(root).push([r, c]);
        }
        for (const groupCells of groups.values()) {
            let maxRank = 0;
            for (const [r, c] of groupCells) {
                maxRank = Math.max(maxRank, rankRow[r], rankCol[c]);
            }
            const newRank = maxRank + 1;
            for (const [r, c] of groupCells) {
                rankRow[r] = newRank;
                rankCol[c] = newRank;
                answer[r][c] = newRank;
            }
        }
    }
    return answer;
};
